#include "file_system_dialog.h"
#include <QFileDialog>
namespace seb::userinterface::desktop::windows { FileSystemDialog::FileSystemDialog(QWidget *parent) : parent_(parent) {} contracts::file_system_dialog::FileSystemDialogResult FileSystemDialog::exec() { selectedPath_ = operation_ == contracts::file_system_dialog::FileSystemOperation::SelectFolder ? QFileDialog::getExistingDirectory(parent_) : QFileDialog::getOpenFileName(parent_); return selectedPath_.isEmpty() ? contracts::file_system_dialog::FileSystemDialogResult::Cancel : contracts::file_system_dialog::FileSystemDialogResult::Accept; } QString FileSystemDialog::selectedPath() const { return selectedPath_; } void FileSystemDialog::setOperation(contracts::file_system_dialog::FileSystemOperation operation) { operation_ = operation; } }
